DB_PATH = "data/bot.db"

def get_token():
    for fname in ["trading_bot.py", "bot.py"]:
        if not os.path.exists(fname):
            continue
        with open(fname, "r", encoding="utf-8") as f:
            for line in f:
                ls = line.strip()
                if "TOKEN" in ls.upper() and "=" in ls and ":" in ls:
                    for q in ['"', "'"]:
                        parts = ls.split(q)
                        for p in parts:
                            p = p.strip()
                            if len(p) > 30 and p.count(":") == 1:
                                return p
    return None

def setup_db(db_path, users):
    os.makedirs("data", exist_ok=True)
    conn = sqlite3.connect(db_path)
    c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tg_id TEXT UNIQUE NOT NULL,
        name TEXT,
        is_banned INTEGER DEFAULT 0,
        blocked_or_left INTEGER DEFAULT 0,
        is_frozen INTEGER DEFAULT 0,
        created_at TEXT DEFAULT (datetime('now')),
        referrer_id TEXT,
        referral_count INTEGER DEFAULT 0,
        total_earnings REAL DEFAULT 0
    )""")
    added = 0
    for tg_id, name in users.items():
        try:
            c.execute("INSERT OR IGNORE INTO users (tg_id, name) VALUES (?, ?)", (tg_id, name))
            if c.rowcount:
                added += 1
        except Exception:
            pass
    conn.commit()
    conn.close()
    return added

def send_msg(token, chat_id, text):
    url = f"https://api.telegram.org/bot{token}/sendMessage"
    try:
        r = requests.post(url, json={"chat_id": chat_id, "text": text, "parse_mode": "Markdown"}, timeout=10)
        d = r.json()
        return d.get("ok"), d.get("description", "")
    except Exception as e:
        return False, str(e)

